#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=301,Mod=1e9+7,K=1e6+10,SK=5010;
int a[N][N],dp[2][N][SK],pos[K],blk[K],inv[K];
inline int upDiv(int a,int b){return a%b==0?a/b:a/b+1;}
int main()
{
	int n=read(),m=read(),k=read();rep(1,n,i)rep(1,m,j)a[i][j]=read();
	rep(1,k,i)inv[i]=upDiv(k,i);int nxt=1;rep(1,k,i)if(inv[i]^inv[i-1])blk[nxt++]=inv[i],pos[inv[i]]=nxt-1;
//	rep(1,nxt-1,i)printf("%d ",blk[i]);
	dp[1][1][pos[upDiv(k,a[1][1])]]=1;rep(1,n,i)rep(1,m,j)rep(1,nxt-1,q)
	{
		
		int I=i&1;if(i^n)(dp[I^1][j][pos[upDiv(blk[q],a[i+1][j])]]+=dp[I][j][q])%=Mod;
		if(j^m)(dp[I][j+1][pos[upDiv(blk[q],a[i][j+1])]]+=dp[I][j][q])%=Mod;if(i^n||j^m||q^(nxt-1))dp[I][j][q]=0;
//		printf("%d %d %d\n",dp[i][j][2]);
	}
//	rep(1,n,i)rep(1,m,j)rep(1,nxt-1,k)if(dp[i][j][k]>0)printf("%d %d %d %d\n",i,j,k,dp[i][j][k]);
	printf("%d\n",dp[n&1][m][nxt-1]);
}
